"""Planning Agent — analyzes an Issue and generates an execution plan.

Runs BEFORE the Generator (Ralph). Produces a structured plan.md with checklist items.
Can also split complex issues into smaller sub-issues.

Flow:
  Issue (backlog/todo) → planning status
  Planning Agent: analyze codebase + issue → write plan.md
    - Simple issue → plan.md with checklist → issue → todo
    - Complex issue → split into sub-issues with parent_id → parent issue → agent_done
"""

from __future__ import annotations
import json
import re
import time
from pathlib import Path
from typing import Awaitable, Callable

from claude_agent_sdk import (
    query, ClaudeAgentOptions, ResultMessage,
    AssistantMessage, TextBlock, ToolUseBlock,
)
from claude_agent_sdk.types import StreamEvent
from config import MODEL
from core.models import Issue, IssueStatus
from core.storage import ProjectStorage


PROMPTS_DIR = Path("prompts")

C_RESET = "\033[0m"
C_CYAN = "\033[36m"
C_GREEN = "\033[32m"
C_YELLOW = "\033[33m"
C_RED = "\033[31m"
C_MAGENTA = "\033[35m"
C_DIM = "\033[2m"
C_BLUE = "\033[34m"


def _log(prefix: str, color: str, msg: str) -> None:
    try:
        from harness import _tee
        _tee(f"{color}[{prefix}]{C_RESET} {msg}")
    except ImportError:
        print(f"[{prefix}] {msg}", flush=True)


def _log_message(message) -> None:
    if isinstance(message, AssistantMessage):
        for block in message.content:
            if isinstance(block, TextBlock):
                text = block.text[:300] + "..." if len(block.text) > 300 else block.text
                _log("Planning", C_BLUE, text)
            elif isinstance(block, ToolUseBlock):
                inp = str(block.input)[:120]
                _log("Tool", C_YELLOW, f"{block.name}({inp})")
    elif isinstance(message, ResultMessage):
        cost = f"${message.total_cost_usd:.2f}" if message.total_cost_usd else "?"
        _log("Planning", C_GREEN, f"Done. turns={message.num_turns} cost={cost} duration={message.duration_ms // 1000}s")
        if message.is_error:
            _log("Planning", C_RED, f"ERROR: {message.result}")


def _message_to_events(issue_id: str, message) -> list[dict]:
    """Convert SDK message to WebSocket event dicts for the planning phase."""
    ts = int(time.time())
    events: list[dict] = []

    if isinstance(message, StreamEvent):
        evt = message.event
        evt_type = evt.get("type", "")
        if evt_type == "content_block_delta":
            delta = evt.get("delta", {})
            if delta.get("type") == "text_delta":
                text = delta.get("text", "")
                if text:
                    events.append({
                        "ts": ts, "type": "agent_token", "issue_id": issue_id,
                        "data": {"text": text, "phase": "planning"},
                    })
        elif evt_type == "content_block_start":
            cb = evt.get("content_block", {})
            if cb.get("type") == "tool_use":
                events.append({
                    "ts": ts, "type": "agent_tool_call", "issue_id": issue_id,
                    "data": {"tool": cb.get("name", ""), "input": cb.get("input", {}), "phase": "planning"},
                })
    elif isinstance(message, AssistantMessage):
        for block in message.content:
            if isinstance(block, TextBlock):
                events.append({
                    "ts": ts, "type": "agent_token", "issue_id": issue_id,
                    "data": {"text": block.text, "phase": "planning"},
                })
            elif isinstance(block, ToolUseBlock):
                events.append({
                    "ts": ts, "type": "agent_tool_call", "issue_id": issue_id,
                    "data": {"tool": block.name, "input": block.input, "phase": "planning"},
                })
    elif isinstance(message, ResultMessage):
        status = "failed" if message.is_error else "done"
        data: dict = {"status": status, "phase": "planning"}
        if message.is_error:
            data["error"] = message.result
        if message.total_cost_usd:
            data["cost_usd"] = message.total_cost_usd
        if message.duration_ms:
            data["duration_ms"] = message.duration_ms
        if message.num_turns:
            data["num_turns"] = message.num_turns
        events.append({
            "ts": ts, "type": "agent_status", "issue_id": issue_id,
            "data": data,
        })

    return events


def _build_planning_prompt(issue: Issue, storage: ProjectStorage, workspace: Path) -> str:
    """Build the prompt for the Planning Agent."""
    try:
        content = storage.load_issue_content(issue.id)
    except FileNotFoundError:
        content = ""

    existing_plan = storage.load_issue_plan(issue.id)
    plan_path = storage.issues_dir / issue.id / "plan.md"

    agent_md_path = workspace / "AGENT.md"
    agent_md = agent_md_path.read_text() if agent_md_path.exists() else ""

    specs_content = ""
    for specs_dir in [workspace / ".harness" / "specs", storage.root / "specs"]:
        if specs_dir.exists():
            for f in sorted(specs_dir.glob("*.md")):
                specs_content += f"\n\n### {f.name}\n{f.read_text()}"

    # Gather info about child issues if any exist
    all_issues = storage.list_issues()
    child_issues = [i for i in all_issues if i.parent_id == issue.id]
    sibling_context = ""
    if issue.parent_id:
        siblings = [i for i in all_issues if i.parent_id == issue.parent_id and i.id != issue.id]
        if siblings:
            sibling_context = "\n## 同级子 Issue\n"
            for s in siblings:
                sibling_context += f"- {s.id}: {s.title} (status: {s.status.value})\n"

    children_context = ""
    if child_issues:
        children_context = "\n## 已有子 Issue\n"
        for c in child_issues:
            children_context += f"- {c.id}: {c.title} (status: {c.status.value})\n"

    return f"""请为以下 Issue 制定执行计划。

## Issue 信息

- ID: {issue.id}
- 标题: {issue.title}
- 优先级: {issue.priority.value}
- 标签: {', '.join(issue.labels) if issue.labels else '无'}
- 父 Issue: {issue.parent_id or '无'}

## 详细描述

{content if content else '（无详细描述，请根据标题分析）'}

## 现有计划

{existing_plan if existing_plan else '（尚无计划）'}
{sibling_context}
{children_context}

## plan.md 路径

请将计划写入: {plan_path}

## 项目构建指南 (AGENT.md)
{agent_md}

## 功能规格 (specs/)
{specs_content}

## 要求

1. 先用 Read/Glob/Grep 探索代码库，理解现有架构
2. 分析此 Issue 的复杂度
3. 如果任务可以在 3-5 个文件内完成，生成详细的执行计划写入 plan.md
4. 如果任务过于复杂（参考复杂度评估标准），在 plan.md 中使用 [SPLIT] 标记建议拆分
5. 必须将计划写入上述 plan.md 路径
"""


def parse_planning_result(plan_content: str) -> dict:
    """Parse the plan.md content to extract split directives and plan items.

    Returns:
        {
            "has_splits": bool,
            "splits": [{"title": str, "description": str}, ...],
            "plan_items": ["step1", "step2", ...],
            "dependencies": str,  # dependency description if splits exist
        }
    """
    result: dict = {
        "has_splits": False,
        "splits": [],
        "plan_items": [],
        "dependencies": "",
    }

    if not plan_content:
        return result

    # Extract [SPLIT] directives
    split_pattern = re.compile(r"^-\s*\[SPLIT\]\s*(.+)$", re.MULTILINE)
    for match in split_pattern.finditer(plan_content):
        raw = match.group(1).strip()
        # Format: "title | description" or just "title"
        if "|" in raw:
            title, desc = raw.split("|", 1)
            result["splits"].append({
                "title": title.strip(),
                "description": desc.strip(),
            })
        else:
            result["splits"].append({
                "title": raw,
                "description": "",
            })

    result["has_splits"] = len(result["splits"]) > 0

    # Extract checklist items (plan steps)
    checklist_pattern = re.compile(r"^-\s*\[[ x]\]\s*(.+)$", re.MULTILINE)
    for match in checklist_pattern.finditer(plan_content):
        item = match.group(1).strip()
        # Skip items that are [SPLIT] directives
        if not item.startswith("[SPLIT]"):
            result["plan_items"].append(item)

    # Extract dependency section
    dep_section = re.search(r"##\s*依赖关系\s*\n([\s\S]*?)(?=\n##|\Z)", plan_content)
    if dep_section:
        result["dependencies"] = dep_section.group(1).strip()

    return result


def _create_child_issue(
    title: str,
    description: str,
    storage: ProjectStorage,
    parent_issue: Issue,
    blocked_by: list[str] | None = None,
) -> Issue:
    """Create a child issue from a split directive."""
    project = storage.load_project_meta()
    prefix = project.key if project else "ISS"
    issue_id = storage.next_issue_id(prefix)

    child = Issue.create(id=issue_id, title=title, labels=["planning-split"])
    child.source = "agent"
    child.parent_id = parent_issue.id
    child.priority = parent_issue.priority

    # Copy parent's labels (except internal ones)
    for label in parent_issue.labels:
        if label not in child.labels:
            child.labels.append(label)

    if blocked_by:
        child.blocked_by = blocked_by

    # Save issue and its content
    storage.save_issue(child)
    if description:
        storage.save_issue_content(issue_id, description)

    # Add to board
    board_file = storage.root / "board.json"
    if board_file.exists():
        data = json.loads(board_file.read_text())
        for col in data["columns"]:
            if col["id"] == "backlog":
                col["issues"].append(child.id)
                break
        board_file.write_text(json.dumps(data, indent=2, ensure_ascii=False))

    _log("Planning", C_CYAN, f"Created child issue {child.id}: {title} (parent: {parent_issue.id})")
    return child


async def run_planning_agent(
    issue: Issue,
    storage: ProjectStorage,
    workspace: Path,
    on_event: Callable[[dict], Awaitable[None]] | None = None,
) -> dict:
    """Run the Planning Agent for a single Issue.

    Returns:
        {
            "success": bool,
            "cost_usd": float,
            "duration_ms": int,
            "num_turns": int,
            "has_splits": bool,
            "child_issue_ids": [str, ...],
            "plan_items_count": int,
        }
    """
    from config import MAX_PLANNING_TURNS, MAX_PLANNING_BUDGET

    _log("Planning", C_BLUE, f"Starting planning for {issue.id}: {issue.title}")

    system_prompt_path = PROMPTS_DIR / "planning_agent_system.md"
    system_prompt = system_prompt_path.read_text() if system_prompt_path.exists() else ""

    prompt = _build_planning_prompt(issue, storage, workspace)

    stats: dict = {
        "success": False,
        "cost_usd": 0,
        "duration_ms": 0,
        "num_turns": 0,
        "has_splits": False,
        "child_issue_ids": [],
        "plan_items_count": 0,
    }

    # Emit planning status
    if on_event:
        await on_event({
            "ts": int(time.time()), "type": "agent_status", "issue_id": issue.id,
            "data": {"status": "planning", "phase": "planning"},
        })

    async for message in query(
        prompt=prompt,
        options=ClaudeAgentOptions(
            model=MODEL,
            system_prompt=system_prompt,
            allowed_tools=["Read", "Write", "Edit", "Glob", "Grep"],
            cwd=str(workspace),
            max_turns=MAX_PLANNING_TURNS,
            max_budget_usd=MAX_PLANNING_BUDGET,
            permission_mode="bypassPermissions",
        ),
    ):
        _log_message(message)

        if on_event:
            for event in _message_to_events(issue.id, message):
                await on_event(event)

        if isinstance(message, ResultMessage):
            stats.update({
                "success": not message.is_error,
                "cost_usd": message.total_cost_usd or 0,
                "duration_ms": message.duration_ms,
                "num_turns": message.num_turns,
                "usage": message.usage or {},
            })

    # After planning agent completes, read the plan.md it wrote
    plan_content = storage.load_issue_plan(issue.id)

    if plan_content:
        parsed = parse_planning_result(plan_content)
        stats["plan_items_count"] = len(parsed["plan_items"])
        stats["has_splits"] = parsed["has_splits"]

        if parsed["has_splits"]:
            # Create child issues from split directives
            child_ids: list[str] = []
            prev_child_id: str | None = None

            for split in parsed["splits"]:
                # Each subsequent child is blocked by the previous one (sequential dependency)
                blocked_by = [prev_child_id] if prev_child_id else []

                # Parse dependency info if available
                child = _create_child_issue(
                    title=split["title"],
                    description=split["description"],
                    storage=storage,
                    parent_issue=issue,
                    blocked_by=blocked_by,
                )
                child_ids.append(child.id)
                prev_child_id = child.id

            stats["child_issue_ids"] = child_ids
            _log("Planning", C_GREEN,
                 f"Split {issue.id} into {len(child_ids)} child issues: {', '.join(child_ids)}")
    else:
        _log("Planning", C_YELLOW, f"Planning agent did not write plan.md for {issue.id}")

    return stats

